from __future__ import annotations

from dataclasses import dataclass
from enum import Enum
from typing import Iterable


class CronParseError(ValueError):
    """Raised when a cron expression cannot be parsed."""


class FieldKind(Enum):
    ANY = "any"
    SINGLE = "single"
    RANGE = "range"
    LIST = "list"
    STEP = "step"


@dataclass(frozen=True)
class FieldSpec:
    name: str
    raw: str
    minimum: int
    maximum: int
    values: tuple[int, ...]
    kind: FieldKind

    @property
    def is_any(self) -> bool:
        return self.kind == FieldKind.ANY

    @property
    def is_single(self) -> bool:
        return self.kind == FieldKind.SINGLE and len(self.values) == 1

    @property
    def single_value(self) -> int:
        if not self.is_single:
            raise ValueError(f"{self.name} is not a single value")
        return self.values[0]


@dataclass(frozen=True)
class CronSchedule:
    minute: FieldSpec
    hour: FieldSpec
    day_of_month: FieldSpec
    month: FieldSpec
    day_of_week: FieldSpec

    def describe(self) -> str:
        if all(field.is_any for field in self.fields):
            return "Every minute"

        if self.minute.kind == FieldKind.STEP and self._all_except("minute"):
            step = _extract_step(self.minute.raw)
            return f"Every {step} minutes"

        if self.hour.kind == FieldKind.STEP and self.minute.values == (0,) and self._date_fields_are_any():
            step = _extract_step(self.hour.raw)
            return f"Every {step} hours, on the hour"

        if self.minute.is_single and self.hour.is_single:
            time_text = _format_time(self.hour.single_value, self.minute.single_value)
            date_text = self._describe_date_part()

            if date_text:
                return f"At {time_text} {date_text}"
            return f"At {time_text}"

        return self._describe_general_schedule()

    @property
    def fields(self) -> tuple[FieldSpec, FieldSpec, FieldSpec, FieldSpec, FieldSpec]:
        return (
            self.minute,
            self.hour,
            self.day_of_month,
            self.month,
            self.day_of_week,
        )

    def _all_except(self, field_name: str) -> bool:
        return all(field.is_any for field in self.fields if field.name != field_name)

    def _date_fields_are_any(self) -> bool:
        return (
            self.day_of_month.is_any
            and self.month.is_any
            and self.day_of_week.is_any
        )

    def _describe_date_part(self) -> str:
        parts: list[str] = []

        if not self.day_of_month.is_any:
            parts.append(_describe_day_of_month(self.day_of_month))

        if not self.month.is_any:
            parts.append(_describe_month(self.month))

        if not self.day_of_week.is_any:
            parts.append(f"on {_describe_day_of_week(self.day_of_week)}")

        return " ".join(parts)

    def _describe_general_schedule(self) -> str:
        parts = [
            _describe_field("minute", self.minute),
            _describe_field("hour", self.hour),
            _describe_field("day of month", self.day_of_month),
            _describe_field("month", self.month),
            _describe_field("day of week", self.day_of_week),
        ]
        return "; ".join(part for part in parts if part)


FIELD_DEFINITIONS: dict[str, tuple[int, int]] = {
    "minute": (0, 59),
    "hour": (0, 23),
    "day_of_month": (1, 31),
    "month": (1, 12),
    "day_of_week": (0, 6),
}

DAY_NAMES: dict[int, str] = {
    0: "Sunday",
    1: "Monday",
    2: "Tuesday",
    3: "Wednesday",
    4: "Thursday",
    5: "Friday",
    6: "Saturday",
}

MONTH_NAMES: dict[int, str] = {
    1: "January",
    2: "February",
    3: "March",
    4: "April",
    5: "May",
    6: "June",
    7: "July",
    8: "August",
    9: "September",
    10: "October",
    11: "November",
    12: "December",
}


def parse_cron(expression: str) -> CronSchedule:
    fields = expression.split()

    if len(fields) != 5:
        raise CronParseError(
            f"Expected 5 cron fields: minute hour day_of_month month day_of_week; "
            f"got {len(fields)}"
        )

    minute = parse_field("minute", fields[0])
    hour = parse_field("hour", fields[1])
    day_of_month = parse_field("day_of_month", fields[2])
    month = parse_field("month", fields[3])
    day_of_week = parse_field("day_of_week", fields[4])

    return CronSchedule(
        minute=minute,
        hour=hour,
        day_of_month=day_of_month,
        month=month,
        day_of_week=day_of_week,
    )


def parse_field(name: str, raw: str) -> FieldSpec:
    if name not in FIELD_DEFINITIONS:
        raise CronParseError(f"Unknown cron field: {name}")

    minimum, maximum = FIELD_DEFINITIONS[name]

    if not raw:
        raise CronParseError(f"{name} field cannot be empty")

    values: set[int] = set()
    parts = raw.split(",")

    for part in parts:
        if not part:
            raise CronParseError(f"{name} contains an empty list item: {raw!r}")
        values.update(_parse_field_part(name, part, minimum, maximum))

    sorted_values = tuple(sorted(values))

    if not sorted_values:
        raise CronParseError(f"{name} does not contain any valid values")

    return FieldSpec(
        name=name,
        raw=raw,
        minimum=minimum,
        maximum=maximum,
        values=sorted_values,
        kind=_classify_field(raw),
    )


def _parse_field_part(
    name: str,
    part: str,
    minimum: int,
    maximum: int,
) -> tuple[int, ...]:
    base, step = _split_step(name, part)

    if base == "*":
        start, end = minimum, maximum
    elif "-" in base:
        start, end = _parse_range(name, base, minimum, maximum)
    else:
        value = _parse_int(name, base)
        _validate_value(name, value, minimum, maximum)
        start, end = value, value

    values = range(start, end + 1, step)
    return tuple(values)


def _split_step(name: str, part: str) -> tuple[str, int]:
    if "/" not in part:
        return part, 1

    pieces = part.split("/")

    if len(pieces) != 2 or not pieces[0] or not pieces[1]:
        raise CronParseError(f"Invalid step syntax in {name}: {part!r}")

    step = _parse_int(name, pieces[1])

    if step <= 0:
        raise CronParseError(f"{name} step must be greater than zero: {part!r}")

    return pieces[0], step


def _parse_range(
    name: str,
    raw_range: str,
    minimum: int,
    maximum: int,
) -> tuple[int, int]:
    pieces = raw_range.split("-")

    if len(pieces) != 2 or not pieces[0] or not pieces[1]:
        raise CronParseError(f"Invalid range syntax in {name}: {raw_range!r}")

    start = _parse_int(name, pieces[0])
    end = _parse_int(name, pieces[1])

    _validate_value(name, start, minimum, maximum)
    _validate_value(name, end, minimum, maximum)

    if start > end:
        raise CronParseError(f"{name} range start cannot exceed range end: {raw_range!r}")

    return start, end


def _parse_int(name: str, raw_value: str) -> int:
    if not raw_value.isdigit():
        raise CronParseError(f"{name} value must be an integer: {raw_value!r}")

    return int(raw_value)


def _validate_value(name: str, value: int, minimum: int, maximum: int) -> None:
    if value < minimum or value > maximum:
        raise CronParseError(
            f"{name} value {value} is out of range; expected {minimum}-{maximum}"
        )


def _classify_field(raw: str) -> FieldKind:
    if raw == "*":
        return FieldKind.ANY
    if "/" in raw:
        return FieldKind.STEP
    if "," in raw:
        return FieldKind.LIST
    if "-" in raw:
        return FieldKind.RANGE
    return FieldKind.SINGLE


def _extract_step(raw: str) -> int:
    return int(raw.split("/", 1)[1])


def _format_time(hour: int, minute: int) -> str:
    if hour == 0 and minute == 0:
        return "midnight"
    return f"{hour:02d}:{minute:02d}"


def _describe_day_of_month(field: FieldSpec) -> str:
    if field.is_single:
        return f"on the {_ordinal(field.single_value)} of every month"

    return f"on days {_join_words(_ordinal(value) for value in field.values)}"


def _describe_month(field: FieldSpec) -> str:
    month_names = [MONTH_NAMES[value] for value in field.values]

    if field.is_single:
        return f"in {month_names[0]}"

    return f"in {_join_words(month_names)}"


def _describe_day_of_week(field: FieldSpec) -> str:
    if field.kind == FieldKind.RANGE:
        first = DAY_NAMES[field.values[0]]
        last = DAY_NAMES[field.values[-1]]
        return f"{first} through {last}"

    names = [DAY_NAMES[value] for value in field.values]
    return _join_words(names)


def _describe_field(label: str, field: FieldSpec) -> str:
    if field.is_any:
        return ""

    if field.kind == FieldKind.STEP:
        return f"{label}: every {_extract_step(field.raw)}"

    if field.kind == FieldKind.RANGE:
        return f"{label}: {field.values[0]} through {field.values[-1]}"

    return f"{label}: {_join_words(str(value) for value in field.values)}"


def _ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


def _join_words(words: Iterable[str]) -> str:
    items = list(words)

    if not items:
        return ""

    if len(items) == 1:
        return items[0]

    if len(items) == 2:
        return f"{items[0]} and {items[1]}"

    return f"{', '.join(items[:-1])}, and {items[-1]}"


if __name__ == "__main__":
    examples = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]

    for expression in examples:
        schedule = parse_cron(expression)
        print(expression, "->", schedule.describe())
